add_action('init', function() {
    if ( ! isset($_GET['count_published']) || ! current_user_can('manage_options') ) return;
    global $wpdb;

    $total_publish = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$wpdb->posts} WHERE post_type='product' AND post_status='publish'");

    $zb_publish = (int) $wpdb->get_var("
        SELECT COUNT(*) FROM {$wpdb->posts} p
        JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        WHERE p.post_type='product' AND p.post_status='publish'
    ");

    $non_zb_publish = $total_publish - $zb_publish;

    echo '<style>body{font-family:monospace;padding:20px;font-size:15px} td{border:1px solid #ccc;padding:6px 14px}</style>';
    echo "<h2>Paskelbtos prekės</h2><table>";
    echo "<tr><td>Iš viso publish</td><td><b>$total_publish</b></td></tr>";
    echo "<tr><td>ZB prekės (publish)</td><td><b>$zb_publish</b></td></tr>";
    echo "<tr><td>Ne-ZB prekės (publish)</td><td><b>$non_zb_publish</b></td></tr>";
    echo "</table>";
    exit;
});

/**
 * Sale Clean v1 (Legacy palikimo akciju valymas)
 *
 * PASKIRTIS: isvalyti _sale_price 26 Legacy-palikimo prekems (Josera/Josi/Churu),
 * kur excel scriptas uzrase apgaulinga akcija (base = personal, ne tikra VF akcija).
 *
 * VEIKSMAS kiekvienai tinkamai prekei:
 *   1. delete _sale_price (akcija dingsta)
 *   2. _price = _regular_price (klientas moka regular, kaina pakyla)
 *   3. wc_delete_product_transients (frontend atsinaujina — S72 pamoka)
 *
 * APSAUGOS (preke valoma TIK jei VISOS salygos tenkinamos):
 *   - turi _sale_price (netuscia)
 *   - NETURI _sale_price_dates_from/to (ne terminuota akcija — ne Ambrosia)
 *   - _vf_cost_xml ir _vf_personal_xml: base >= personal ARBA personal tuscias
 *     (= NE tikra VF akcija; tikros VF akcijos base < personal — NELIESTI)
 *
 *   Si trigubo patikra = ta pati klasifikacija kaip Sale Classify v1.
 *   FURminator/FLEXI (base < personal) NEPATENKA -> apsaugoti.
 *   Ambrosia (su datomis) NEPATENKA -> apsaugoti.
 *
 * DRY-RUN default. Realiam valymui: &confirm=CLEAN_SALE
 * Backup CSV: uploads/petshop-private-logs/sale-clean-backup.csv
 *
 * NAUDOJIMAS:
 *   Dry-run:  /wp-admin/?sale_clean=1
 *   Apply:    /wp-admin/?sale_clean=1&confirm=CLEAN_SALE
 * Po naudojimo deaktyvuoti.
 */

add_action( 'init', function () {

	if ( ! isset( $_GET['sale_clean'] ) ) return;
	if ( ! current_user_can( 'manage_options' ) ) return;

	@set_time_limit( 300 );
	global $wpdb;

	$confirm = isset($_GET['confirm']) && $_GET['confirm'] === 'CLEAN_SALE';

	header( 'Content-Type: text/html; charset=utf-8' );
	echo '<meta charset="utf-8"><body style="font-family:monospace;font-size:13px;padding:20px;line-height:1.5">';
	echo '<h2>Sale Clean v1 ' . ( $confirm ? '<span style="color:red">[APPLY]</span>' : '<span style="color:green">[DRY-RUN]</span>' ) . '</h2>';

	// Visos publish prekes su _sale_price
	$ids = $wpdb->get_col( "
		SELECT DISTINCT pm.post_id
		FROM {$wpdb->postmeta} pm
		INNER JOIN {$wpdb->posts} p ON p.ID = pm.post_id
		WHERE pm.meta_key = '_sale_price'
		  AND pm.meta_value != ''
		  AND pm.meta_value IS NOT NULL
		  AND p.post_type = 'product'
		  AND p.post_status = 'publish'
	" );

	// Atrenkam TIK Legacy palikima (ta pati logika kaip Classify)
	$to_clean = [];
	foreach ( $ids as $pid ) {
		$sale = get_post_meta($pid,'_sale_price',true);
		if ( $sale === '' ) continue;

		// Su datomis -> NELIESTI (Ambrosia)
		$from = get_post_meta($pid,'_sale_price_dates_from',true);
		$to   = get_post_meta($pid,'_sale_price_dates_to',true);
		if ( $from || $to ) continue;

		$base_xml     = get_post_meta($pid,'_vf_cost_xml',true);
		$personal_xml = get_post_meta($pid,'_vf_personal_xml',true);

		// Nera VF duomenu visai -> NELIESTI (saugumas)
		if ( $base_xml === '' && $personal_xml === '' ) continue;

		$base = (float) $base_xml;
		$personal = (float) $personal_xml;

		// TIKRA VF akcija (base < personal) -> NELIESTI
		if ( $base > 0 && $personal > 0 && $base < $personal ) continue;

		// Liko: base >= personal arba personal tuscias -> Legacy palikimas -> VALYTI
		$to_clean[] = $pid;
	}

	echo '<p>Rasta valymui: <b style="color:red">' . count($to_clean) . '</b> prekiu (Legacy palikimas).</p>';

	// Backup tik apply metu
	$backup_path = '';
	$backup_handle = null;
	if ( $confirm ) {
		$updir = wp_upload_dir();
		$log_dir = $updir['basedir'] . '/petshop-private-logs';
		if ( ! file_exists($log_dir) ) wp_mkdir_p($log_dir);
		$backup_path = $log_dir . '/sale-clean-backup.csv';
		$backup_handle = fopen($backup_path, 'w');
		if ( $backup_handle ) {
			fputcsv($backup_handle, ['post_id','title','old_regular','old_sale','old_price','new_price','timestamp']);
		}
	}

	echo '<table border="1" cellpadding="5" cellspacing="0" style="font-size:11px"><tr>'
	   . '<th>ID</th><th>Pavadinimas</th><th>regular</th><th>sale (trinama)</th>'
	   . '<th>senas _price</th><th>naujas _price</th><th>statusas</th></tr>';

	$done = 0;
	foreach ( $to_clean as $pid ) {
		$regular = get_post_meta($pid,'_regular_price',true);
		$sale    = get_post_meta($pid,'_sale_price',true);
		$price   = get_post_meta($pid,'_price',true);
		$new_price = $regular; // regular lieka, sale dingsta

		$status = $confirm ? '<span style="color:red">ISVALYTA</span>' : '<span style="color:green">bus isvalyta</span>';

		if ( $confirm ) {
			// 1. delete sale
			delete_post_meta($pid,'_sale_price');
			// 2. _price = regular
			update_post_meta($pid,'_price',$new_price);
			// 3. transients
			if ( function_exists('wc_delete_product_transients') ) {
				wc_delete_product_transients($pid);
			}
			clean_post_cache($pid);
			// backup
			if ( $backup_handle ) {
				fputcsv($backup_handle, [$pid, get_the_title($pid), $regular, $sale, $price, $new_price, current_time('mysql')]);
			}
			$done++;
		}

		echo '<tr>'
		   . '<td>' . $pid . '</td>'
		   . '<td>' . esc_html(mb_substr(get_the_title($pid),0,35)) . '</td>'
		   . '<td>' . esc_html($regular) . '</td>'
		   . '<td style="color:#aaa;text-decoration:line-through">' . esc_html($sale) . '</td>'
		   . '<td>' . esc_html($price) . '</td>'
		   . '<td style="color:green;font-weight:bold">' . esc_html($new_price) . '</td>'
		   . '<td>' . $status . '</td>'
		   . '</tr>';
	}
	echo '</table>';

	if ( $backup_handle ) fclose($backup_handle);

	if ( $confirm ) {
		echo '<p style="color:red;font-weight:bold">ISVALYTA: ' . $done . ' prekiu.</p>';
		if ( $backup_path ) echo '<p>Backup: ' . esc_html($backup_path) . '</p>';
		echo '<p>Patikrink prekes frontend\'e — akcijos turi but dingusios, kaina = regular.</p>';
	} else {
		echo '<p style="color:green">DRY-RUN. Niekas nepakeista. Realiam valymui prideti: <code>&confirm=CLEAN_SALE</code></p>';
	}

	echo '<hr><p style="color:#666">Po naudojimo deaktyvuoti.</p></body>';
	exit;
} );
